-- For each multi-author book, insert a copy attributed to the second author
-- (The original row stays attributed to the first author after we update it)

-- Aaron Ross and Jason Lemkin books -> add Jason Lemkin rows
INSERT IGNORE INTO book_profiles (bookTitle, authorName, s3CoverUrl, coverUrl, amazonUrl, goodreadsUrl, summary, keyThemes, rating, isbn, publisher, enrichedAt, s3CoverKey)
SELECT bookTitle, 'Jason Lemkin', s3CoverUrl, coverUrl, amazonUrl, goodreadsUrl, summary, keyThemes, rating, isbn, publisher, enrichedAt, s3CoverKey
FROM book_profiles WHERE authorName IN ('Aaron Ross and Jason Lemkin');

-- Update original rows to use individual author name
UPDATE book_profiles SET authorName = 'Aaron Ross' WHERE authorName = 'Aaron Ross and Jason Lemkin';

